19	const PROCESSING_FEE = 5;
20	
21	const BASE_PRICE_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
30	
31	const COMPONENT_BLOCK_PRICE = 60;
32	const COMPONENT_TYPES = new Set(["rune"]);
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const itemsBasePremium = (items: Item[]): number => {
37	  const components = items.filter(isComponent);
38	  const nonComponents = items.filter((i) => !isComponent(i));
39	  const nonCompTotal = nonComponents.reduce((s, i) => s + basePriceFor(i), 0);
40	  const blocks = Math.floor(components.length / 3);
41	  const singles = components.length - blocks * 3;
42	  const compTotal = blocks * COMPONENT_BLOCK_PRICE + singles * 25;
43	  return nonCompTotal + compTotal;
44	};
45	
46	const quotePremium = (step: QuoteStep): number =>
47	  itemsBasePremium(step.items) + PROCESSING_FEE;
48	
49	export const runScenario = (scenario: Scenario): ScenarioResult => ({
50	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
51	});
